INSERT INTO "update" VALUES(1,'55c20b59d0793587aa98d92fb74452a06d60ae79','feat: existing song search on add artist page, hex paste on theme edit - Add global /edit/search-songs endpoint for song lookup without artist context - Add artist page song name input doubles as search for existing songs - Existing songs link to new album with featured artist association - Theme edit hex codes are now editable text inputs for paste/type - Click-to-copy still works on hex inputs when not focused','2026-04-04 21:36:00');
INSERT INTO "update" VALUES(2,'b8f29fc015305b893402bd0e79de3a5af7da40b8','feat: add existing album search on add artist page - Add /edit/search-albums endpoint for album lookup by name - Existing Album button opens search dropdown next to Add Album - Selecting an existing album links all its songs to the new artist - Skip validation for existing albums in both client and server','2026-04-04 22:00:00');
INSERT INTO "update" VALUES(3,'a52993e7fe083149ad6fc170ed0d57a9fc950285','fix: ampersand displaying as &amp; in manage artists popover Use tojson instead of |e filter for artist names in JS context','2026-04-04 22:06:00');
INSERT INTO "update" VALUES(5,'9e28af4b2fd6207fccca75339df5db09e629682a','fix: auto-create missing user theme rows on startup','2026-04-04 22:16:00');
INSERT INTO "update" VALUES(6,'95df328ee69e2b2bb3fcb3516796270e54414c80','feat: reorder songs within album via up/down buttons in edit mode','2026-04-04 22:24:00');
INSERT INTO "update" VALUES(7,'414161e449944b15ff0534e2cf2603751ac165aa','fix: album date editor uses text input with auto-format instead of locale-dependent date picker','2026-04-04 22:36:00');
INSERT INTO "update" VALUES(8,'3b54004b524273aa880b5060ebf20a327ea27fad','fix: add artist submit button stuck disabled, shared date formatter - Scope album selector to #albums-container children to avoid matching #album-search-box - Extract applyDateFormat as shared component, convert all date inputs - Add htmx:afterSettle hook for date formatting on dynamic fragments - Reset validation border color on input','2026-04-04 22:48:00');
INSERT INTO "update" VALUES(9,'d2cd76cb1f36e805d4706035be70ddd40cdf4102','perf: consolidate startup migrations into single app context block to improve deployment speed and reduce downtime on deployments','2026-04-04 22:52:00');
INSERT INTO "update" VALUES(10,'731439596a9b62f46874c1ddc7fe87bb9f4ca8a4','fix: use --unrated-text colour for pct-rated cells on artist stats page','2026-04-04 23:11:00');
INSERT INTO "update" VALUES(11,'0a63cad129eeb007b7e30187458857b34c83a5bf','feat: hyperlink artist/song names in changelog, fix rating cell border repaint - Add description_html property with linked artist/song names in changelog - Song links scroll to song row via #song-{id} anchor - Eager-load changelog relationships to avoid N+1 queries - Force row repaint after HTMX and SSE outerHTML swaps to fix collapsed borders','2026-04-04 23:31:00');
INSERT INTO "update" VALUES(13,'b87282c9bedc5778959176ed5e7cf85e424e73bb','fix: redirecting to a song or album now brings you to the album at the correct scrolling position','2026-04-04 23:40:00');
INSERT INTO "update" VALUES(14,'d357f982bb461470ead8f98bc386e5bfe1074aa4','fix: skip changelog entry when rating or note is unchanged','2026-04-04 23:43:00');
INSERT INTO "update" VALUES(15,'34a5656ef1d6cd5237451a35a6187abdae757675','feat: add is_complete and is_disbanded checkboxes to artist edit and add artist page','2026-04-04 23:49:00');
INSERT INTO "update" VALUES(16,'687a280b4f634438a2eae26612d5ff9d353cb19a','fix: disbanded checkbox not working on views page Script tags inserted via innerHTML are not executed by browsers, so the markDisbanded function was never defined. Inline the fetch logic into the onchange attribute instead.','2026-04-05 00:01:00');
INSERT INTO "update" VALUES(17,'f41128159070596710f422188cb5e71b9cadf8e6','fix: note indicator triangle now matches score text color Use currentColor instead of var(--text-primary) so the triangle inherits the cell''s text color set by the rating color scheme.','2026-04-05 00:08:00');
INSERT INTO "update" VALUES(18,'fb9e8906e7113e27d69c7a47f85bcd2cf687cfb4','style: increase note indicator triangle to 10px','2026-04-05 00:09:00');
INSERT INTO "update" VALUES(19,'560f1ac4fb68ebcd9f6e60b6e34e97cc921023c8','feat: add potentially disbanded artists section to views page Shows artists with no releases in the last 5 years who aren''t already marked as disbanded, with a count on the main views page.','2026-04-05 00:11:00');
INSERT INTO "update" VALUES(20,'c44e7bbc492b91939b7f51a1e506514d52e962fa','fix: promoted checkbox toggle Add "Incomplete tabs" section to views page listing artists without is_complete set.  Fix promoted checkbox to toggle the border-left indicator and tag instead of setting a pink background. Remove dead backgroundColor logic.','2026-04-05 01:02:00');
INSERT INTO "update" VALUES(22,'45c724cf4a7bd6980078d8d674e0222dda473b34','feat: anime-aware collab labels (by/for instead of with) On anime artist pages, non-anime main collaborators show as "(by Artist)" instead of "(with Artist)". On non-anime pages, anime main collaborators show as "(for Artist)". Featured labels are unchanged and appear after by/for.','2026-04-05 01:29:00');
INSERT INTO "update" VALUES(23,'f59cb0fb2e49e0a0be1f4234a2fa58cd91dca687','feat: add collapse toggle for subunit/soloist sections Clicking the child header row toggles visibility of all its albums and songs. Works in both edit mode and normal view.','2026-04-05 01:35:00');
INSERT INTO "update" VALUES(24,'345ef26aa408f38d7c95c18edc6f8dbb11558f0f','fix: remove 7-result limit from search queries','2026-04-05 01:39:00');
INSERT INTO "update" VALUES(25,'0f70bbe61b89f2039c6e4ee5710f0c98b8120c76','fix: remove result limits from edit-mode search endpoints','2026-04-05 01:41:00');
INSERT INTO "update" VALUES(26,'3b52a95217a9f3282af3e3956fb76c566d6ad3b4','feat: multi-term search across song, album, and artist names Split multi-word queries so each term can match song name, album name, or artist name. Single-word queries unchanged. Also fix note tooltip overflow on long words.','2026-04-05 01:55:00');
INSERT INTO "update" VALUES(27,'e5f7ea112bd7f57410d1a6a78c85d82c78cfdebf','feat: add collapse toggle for albums with persistent state - Album rows can now be collapsed/expanded by clicking the album header, matching the existing subunit/soloist toggle pattern. Collapse state for both albums and child sections persists across edit mode toggles via sessionStorage.','2026-04-05 02:03:00');
INSERT INTO "update" VALUES(30,'57fd9f1291b70ec3b5963759c3dd5221da6e0a81','fix: always show Misc. Artists in navbar regardless of filters Misc. Artists was being removed by country/genre filters before the pinning logic ran, causing it to sometimes disappear from the hamburger menu. Now exempt from both filters so it always appears pinned at top.','2026-04-05 02:26:00');
INSERT INTO "update" VALUES(31,'dda4aefe8639c732f5f08f1b710fe28db9133391','feat: add theme-configurable hover_bg for dropdown highlights Add hover_bg column to Theme model with migration script. Dropdown hover color is stored as hex and rendered at 20% opacity via JS, fixing unreadable text on dark themes where the old hardcoded light gray clashed with light text. Also adds collapsible sections to search results dropdown.','2026-04-05 02:37:00');
INSERT INTO "update" VALUES(32,'c015a2e42fa76f32ad5a132ab54b544ad22bec8e','feat: admin page with genre/country management and Misc. Artists auto-stubs Add admin page (/admin) with forms to add genres and countries. When added, Misc. Artists country subunits and genre albums are auto-created via shared sync_misc_artist_stubs() service. Restructured Misc. Artists hierarchy: country subunits with genre albums (was genre subunits with country albums). Albums now support direct artist_id FK for empty albums that appear in discography without needing songs. Protected empty albums with artist_id from cleanup in all delete/move paths.','2026-04-05 03:34:00');
INSERT INTO "update" VALUES(33,'6071ed75161b2ca6927e71352f99e1f0909ab9a4','feat: updates page with commit tracking and admin management Add Updates tab showing date, description, and commit ID for each release. Admins can add, edit, and delete entries. Dates stored in 24h format, displayed in 12h AM/PM. Backfilled with all commits from today''s session.','2026-04-05 03:55:00');
INSERT INTO "update" VALUES(34,'69e73dae3676207aedd8bfc4dcb1ed1d96d5eff9','feat: update notification with localStorage dismissal, UTC date handling Store update dates in UTC, convert to/from Eastern on entry/display. Notification uses localStorage to track dismissed update ID so it only shows once per new update, persisting across logins and sessions.','2026-04-05 07:00:00');
INSERT INTO "update" VALUES(35,'b78bb57d6b97f12effb3f72fb213ad2ed55e46fb','fix: add album song name input triggers submit button validation The song name input in the Add Album modal was missing an oninput handler to call validateAddAlbum(), so the submit button stayed disabled after typing a new song name.','2026-04-05 07:00:00');
